args.query:
SELECT qli.Id, qli.QuoteId, qli.Product2Id, qli.PricebookEntryId, qli.Quantity, qli.UnitPrice, qli.Discount, qli.TotalPrice
FROM QuoteLineItem qli
WHERE TRIM(REPLACE(qli.QuoteId,'#','')) = TRIM(REPLACE('0Q0Wt000001WSDVKA4','#',''));

